#include<bits/stdc++.h>
using namespace std;
int main(){
	int a,b;
	scanf("%d%d",&a,&b);
	char x[a+10][b+10],y[a+10][b+10];
	for(int i=0;i<a;i++)for(int j=0;j<b;j++)cin>>x[i][j];
	for(int i=0;i<a;i++)for(int j=0;j<b;j++)y[i][j]=48;
    for(int i=0;i<a;i++)
	{
    	for(int j=0;j<b;j++)
		{ 
     		if(x[i][j]=='*')y[i][j]='*';
    		if(x[i][j]=='?')
			{
    			if(x[i][j+1]=='*')y[i][j]++;
				if(x[i][j-1]=='*')y[i][j]++;
				if(x[i-1][j]=='*')y[i][j]++;
				if(x[i+1][j]=='*')y[i][j]++;
				if(x[i+1][j+1]=='*')y[i][j]++;
				if(x[i+1][j-1]=='*')y[i][j]++;
				if(x[i-1][j+1]=='*')y[i][j]++;
				if(x[i-1][j-1]=='*')y[i][j]++;
			}
		}
	}
	for(int i=0;i<a;i++) {
		for(int j=0;j<b;j++)printf("%c",y[i][j]);
		printf("\n");
	}
	return 0;
}
